const text = $json.article || "";
const url = $json.url || "";

if (!text) {
  return [{ json: { language: "en", article: "", url } }];
}

const hebrewMatches = text.match(/[\u0590-\u05FF]/g) || [];
const hebrewRatio = hebrewMatches.length / text.length;
const language = (hebrewRatio > 0.2 && text.length > 200) ? "he" : "en";

console.log(`Language detected: ${language}, ratio: ${hebrewRatio.toFixed(3)}`);

return [{ json: { language, article: text, url, pageTitle: $json.pageTitle || "" } }];

const inputData = $input.first().json;
const html = inputData.data || inputData.html || inputData.body || inputData.content || inputData.response || "";
const url = $('Set URL').first().json.url || "";

if (!html) {
  return [{ json: { error: "No HTML content found", url } }];
}

// Extract page title from <title> tag
let pageTitle = "";
try {
  const titleMatch = html.match(/<title[^>]*>([^<]+)<\/title>/i);
  if (titleMatch) pageTitle = titleMatch[1].replace(/&amp;/g,"&").replace(/&lt;/g,"<").replace(/&gt;/g,">").replace(/&quot;/g,'"').replace(/&#39;/g,"'").trim();
} catch(e) {}

const MAX_LENGTH = 8000;
let text = "";

// Step 1: Extract <p> and <h1-h6>
try {
  const matches = html.match(/<(p|h[1-6])[^>]*>([\s\S]*?)<\/(p|h[1-6])>/gi);
  if (matches) {
    text = matches
      .map(m => m.replace(/<[^>]+>/g, "").trim())
      .filter(t => t.length > 5)
      .join("\n\n");
  }
} catch (e) {}

// Step 2: Fallback to embedded JSON (articleBody)
if (text.length < 100) {
  try {
    const jsonBlocks = html.match(/<script[^>]+type=["']application\/(ld\+json|json)["'][^>]*>([\s\S]*?)<\/script>/gi);
    if (jsonBlocks) {
      for (let block of jsonBlocks) {
        try {
          const clean = block.replace(/<script[^>]*>/i, "").replace(/<\/script>/i, "").trim();
          const parsed = JSON.parse(clean);
          const findText = (obj) => {
            if (!obj || typeof obj !== "object") return null;
            if (obj.articleBody && typeof obj.articleBody === "string") return obj.articleBody;
            if (obj.text && typeof obj.text === "string" && obj.text.length > 100) return obj.text;
            if (Array.isArray(obj)) { for (const el of obj) { const r = findText(el); if (r) return r; } }
            else { for (const key of Object.keys(obj)) { const r = findText(obj[key]); if (r) return r; } }
            return null;
          };
          const result = findText(parsed);
          if (result) { text = result; break; }
        } catch (err) {}
      }
    }
  } catch (e) {}
}

if (!text || text.length < 100) {
  return [{ json: { error: "Article body not found (likely JS-rendered or blocked)", url } }];
}

// Truncate — no chunking, one AI call
if (text.length > MAX_LENGTH) {
  text = text.substring(0, MAX_LENGTH) + "... [truncated]";
}

return [{ json: { article: text, url, pageTitle, originalLength: html.length, extractedLength: text.length } }];

// Set the URL to summarize here
const url = "https://finance.walla.co.il/item/3825113";
return [{ json: { url } }];

console.log("AI Agent raw output:", JSON.stringify($json, null, 2));

// Grab the upstream context (language + url) from Language Detector
const upstream = $('Language Detector1').first().json;
const language = upstream.language || "en";
const url = upstream.url || "";
const pageTitle = upstream.pageTitle || "";

let raw = $json.output || $json.text || $json.content || "";
if (typeof raw !== "string") raw = JSON.stringify(raw);

// Clean markdown fences and normalize
let s = raw
  .replace(/```json\s*/gi, "")
  .replace(/```\s*/g, "")
  .replace(/[\u2018\u2019]/g, "'")
  .replace(/[\u201C\u201D]/g, '"')
  .trim();

let obj = null;
try {
  obj = JSON.parse(s);
  if (typeof obj === "string") obj = JSON.parse(obj);
} catch (e) {
  console.log("JSON parse failed:", e.message);
}

// Regex salvage if parse failed
if (!obj || typeof obj !== "object") {
  const titleMatch = s.match(/"title"\s*:\s*"([^"]+)"/);
  const bulletsMatch = s.match(/"bullets"\s*:\s*\[([\s\S]*?)\]/);
  if (titleMatch && bulletsMatch) {
    const bullets = [...bulletsMatch[1].matchAll(/"([^"]+)"/g)].map(m => m[1]);
    obj = { title: titleMatch[1], bullets };
  }
}

if (!obj) {
  return [{ json: { error: "Failed to parse AI output", raw: s.slice(0, 500), language, url } }];
}

let title = obj.title || "Summary";
let bullets = Array.isArray(obj.bullets) ? obj.bullets : [];

if (bullets.length > 5) bullets = bullets.slice(0, 5);
while (bullets.length < 5) bullets.push("No further details available.");

return [{ json: { title, bullets, language, url, pageTitle, source: "Local" } }];

const {
  title = "Summary",
  bullets = [],
  error = null,
  raw = "",
  url = "",
  pageTitle = "",
  language = "en"
} = $json || {};

if (error) {
  const errorMsg = language === "he" ? "שגיאה בעיבוד המאמר" : "Error processing article";
  const sourceText = language === "he" ? "מקור:" : "Source:";
  return [{
    json: {
      text: `⚠️ ${errorMsg}\n\n${sourceText} ${url ? `<${url}|${url}>` : "Unknown"}\n\n\`\`\`\n${raw?.slice(0, 500) || "No content"}\n\`\`\``
    }
  }];
}

let cleanTitle = String(title)
  .replace(/^["']|["']$/g, "")
  .replace(/[.,"]+$/, "")
  .replace(/automated with this n8n workflow/i, "")
  .trim();

let cleanBullets = (Array.isArray(bullets) ? bullets : [])
  .map(b => String(b).trim())
  .filter(b => b && !/automated with this n8n workflow/i.test(b))
  .map(b => {
    let cleaned = b.replace(/^["']|["']$/g, "").replace(/^[•\-\*\s]+/, "").trim();
    cleaned = cleaned.replace(/\.{2,}/g, ".");
    if (cleaned.length > 0) cleaned = cleaned.charAt(0).toUpperCase() + cleaned.slice(1);
    if (!/[.!?]$/.test(cleaned) && !/[׃׀]$/.test(cleaned)) cleaned += ".";
    return cleaned;
  })
  .filter(Boolean)
  .slice(0, 5);

const defaultBullet = language === "he" ? "לא נמצאו פרטים נוספים." : "No further details available.";
while (cleanBullets.length < 5) cleanBullets.push(defaultBullet);

const RTL = "\u200F";
const summaryLabel = language === "he" ? "סיכום:" : "Summary:";

// Line 1: page title as clickable link (falls back to plain URL)
const displayTitle = pageTitle || url;
const topLine = url ? `<${url}|${displayTitle}>` : displayTitle;

// Line 2: AI summary title
const summaryLine = language === "he"
  ? `:brain: ${summaryLabel} ${RTL}${cleanTitle}${RTL}`
  : `:brain: ${summaryLabel} ${cleanTitle}`;

let parts;
if (language === "he") {
  parts = [
    topLine,
    summaryLine,
    "",
    ...cleanBullets.map((b, i) => `${i + 1}. ${RTL}${b}${RTL}`),
    ""
  ];
} else {
  parts = [
    topLine,
    summaryLine,
    "",
    ...cleanBullets.map(b => `• ${b}`),
    ""
  ];
}

return [{ json: { text: parts.join("\n") } }];
